package uk.ac.ed.ltg.jdm.util;import java.util.List;/** * A class of static methods supplementing existing String methods. */public class StringTools {	public static final char byteToChar(final byte b) {		return (char) ((b) & 0xFF);	}	public static final byte charToByte(final char c) {		return c > 255 ? (byte) '.' : (byte) c;	}	/**	 * Split.	 * 	 * This split method does not operate identically to the standard	 * string-split implementations in that it splits on every occurrence of a	 * separator, even separators at the beginning of a string or multiple	 * separators in a row. This split function is particularly well suited to	 * extracting data from tab delimited files, where some entries may be	 * blank.	 * 	 * @param text	 *            the text	 * @param emptyStrings	 *            the empty strings	 * @param separator	 *            the separator	 * 	 * @return the list	 */	public static final void split(final List list, final String text,			final char separator) {		list.clear();		if (text != null && text.length() > 0) {			int index1 = 0;			int index2 = text.indexOf(separator);			while (index2 >= 0) {				final String token = text.substring(index1, index2);				list.add(token);				index1 = index2 + 1;				index2 = text.indexOf(separator, index1);			}			if (index1 <= text.length() - 1) {				list.add(text.substring(index1));			}		}	}}